	}
	if err := c.Amnezia.validate(); err != nil {
		return err
	}
	if err := c.Scheduler.validate(); err != nil {
		return err
	}
	if err := c.FEC.validate(); err != nil {
		return err
	}
	if err := c.DNS.validate(); err != nil {
