226	// TestPropertyReorderDupLoss is the randomized-trace property: over many seeds,
227	// under adversarial reorder + duplication + loss, the resequencer delivers in
228	// strictly ascending order, exactly once, never fabricates a seq, and never
229	// buffers more than the window (bounded memory). A benign sub-run (no loss, no
230	// window-overflow, no timeout skip) additionally asserts EVERYTHING deliverable
231	// is delivered.
232	func TestPropertyReorderDupLoss(t *testing.T) {
233		const window = 32
234		for seed := int64(0); seed < 200; seed++ {
235			rng := rand.New(rand.NewSource(seed))
236			clk := newFakeClock()
237			timeout := 50 * time.Millisecond
238			r := reseq.New(window, timeout, clk)
239	
240			const n = 500
241			// Build the network trace: each seq may be lost, and delivered copies are
242			// reordered within a bounded look-ahead so the reorder distance stays a
243			// realistic multiple of typical jitter (not unbounded).
244			type ev struct {
245				seq uint64
246				key float64
247			}
248			var events []ev
249			observedAtLeastOnce := make(map[uint64]bool)
250			// Bounded reorder: arrival order = seqs sorted by (seq + jitter) with jitter
251			// in [0, window/2), which bounds the inversion distance to < window/2 — the
252			// same "cross-path skew is bounded" property real links have.
253			reorder := float64(window / 2)
254			for seq := uint64(0); seq < n; seq++ {
255				if rng.Intn(100) < 10 { // 10% loss
256					continue
257				}
258				copies := 1
259				if rng.Intn(100) < 15 { // 15% duplicated
260					copies = 2
261				}
262				for c := 0; c < copies; c++ {
263					events = append(events, ev{seq: seq, key: float64(seq) + rng.Float64()*reorder})
264				}
265				observedAtLeastOnce[seq] = true
266			}
267			sort.SliceStable(events, func(i, j int) bool { return events[i].key < events[j].key })
268	
269			delivered := make([]uint64, 0, n)
270			seen := make(map[uint64]bool)
271			step := 0
272			feed := func(it reseq.Item) {
273				seq := seqOf(it.Payload)
274				if !observedAtLeastOnce[seq] {
275					t.Fatalf("seed %d: delivered seq %d that was never observed (fabricated)", seed, seq)
276				}
277				if seen[seq] {
278					t.Fatalf("seed %d: seq %d delivered twice (not exactly-once)", seed, seq)
279				}
280				seen[seq] = true
281				if len(delivered) > 0 && seq <= delivered[len(delivered)-1] {
282					t.Fatalf("seed %d: out-of-order delivery %d after %d", seed, seq, delivered[len(delivered)-1])
283				}
284				delivered = append(delivered, seq)
285			}
286	
287			for _, e := range events {
288				r.Observe(e.seq, payloadOf(e.seq), testSrc)
289				if b := r.Buffered(); uint64(b) > window {
290					t.Fatalf("seed %d: buffered %d exceeds window %d (unbounded memory)", seed, b, window)
291				}
292				// Interleave draining and occasional clock advances so timeouts fire.
293				if step%3 == 0 {
294					clk.advance(20 * time.Millisecond)
295				}
296				for {
297					it, ok := r.Pop()
298					if !ok {
299						break
300					}
301					feed(it)
302				}
303				step++
304			}
305			// Flush the tail. Each remaining head-of-line gap now gets its OWN full
306			// timeout (the per-gap-deadline fix — criticism 2), so a single frozen-clock
307			// advance no longer collapses every gap at once (that only worked when a
308			// buggy expire reused one already-elapsed deadline for all subsequent gaps).
309			// Advance the clock once per gap — modelling real wall-clock progress — until
310			// the buffer is fully drained. expire always advances past at least one gap
311			// when the deadline has elapsed, so this terminates in <= window iterations.
312			for r.Buffered() > 0 {
313				clk.advance(timeout + time.Second)
314				for {
315					it, ok := r.Pop()
316					if !ok {
317						break
318					}
319					feed(it)
320				}
321			}
322			for {
323				it, ok := r.Pop()
324				if !ok {
325					break
326				}
327				feed(it)
328			}
329	
330			if b := r.Buffered(); b != 0 {
331				t.Fatalf("seed %d: %d frames still buffered after full flush (held forever)", seed, b)
332			}
333			if hw := r.HighWater(); uint64(hw) > window {
334				t.Fatalf("seed %d: high-water %d exceeds window %d", seed, hw, window)
335			}
336		}
337	}
